import{_ as t,o as e,c as r,R as a}from"./chunks/framework.3P8jtWKJ.js";const f=JSON.parse('{"title":"代码格式化器 Formatter","description":"","frontmatter":{},"headers":[],"relativePath":"zh-CN/guide/formatter/index.md","filePath":"zh-CN/guide/formatter/index.md","lastUpdated":1701307173000}'),o={name:"zh-CN/guide/formatter/index.md"},i=a('<h1 id="代码格式化器-formatter" tabindex="-1">代码格式化器 Formatter <a class="header-anchor" href="#代码格式化器-formatter" aria-label="Permalink to &quot;代码格式化器 Formatter&quot;">​</a></h1><p>代码格式化器是只关心代码风格、不关心代码质量的工具，可配置项有限。使用代码格式化器可以节省代码风格的争论时间，使项目和团队代码风格统一。</p><p><a href="./prettier.html">Prettier</a> 是被广泛采用的代码格式化器，它对 JavaScript / TypeScript / JSX / TSX / CSS / SCSS / Vue 支持良好，也是我首推的代码格式化器。</p><p><a href="./biome.html">Biome</a> 和 <a href="./dprint.html">dprint</a> 是后起之秀。如果你认为 Prettier 速度比较慢，你可以考虑使用它们。但必须留意：它们和 Prettier 并不是 100% 兼容的，你可能会得到意想不到的结果。</p><div class="warning custom-block"><p class="custom-block-title">不要混用代码格式化器</p><p>在任何情况下，你都不应该在生产代码上混用多个代码格式化器。</p></div>',5),s=[i];function c(d,n,p,_,m,l){return e(),r("div",null,s)}const S=t(o,[["render",c]]);export{f as __pageData,S as default};
